module gray_counter(
    input clk,
    input reset,
    output reg [3:0] gray
    );

    reg [3:0] invalid_count;

    always @(posedge clk) begin
        if (reset) begin
            invalid_count <= 4'b0000;
        end else begin
            invalid_count <= invalid_count + 1;
        end
    end

    always @(invalid_count) begin
        gray = (invalid_count >> 1) ^ invalid_count;
    end
endmodule
